sql:
SELECT sign_id, category, images, location 
FROM traffic_signs 
WHERE total_images > 100;

SELECT 
  (SELECT COUNT(*) FROM users WHERE role <> 'model developer') AS non_model_developers,
  (SELECT SUM(total_images) FROM traffic_signs) AS total_training_images;

SELECT category, COUNT(*) AS Traffic_Sign_Count
FROM traffic_signs
GROUP BY category;

SELECT COUNT(*) AS Number_of_Non_Compliant_Signs
FROM regulatory_compliance
WHERE is_compliant = 0;

SELECT model_name
FROM recognition_models
WHERE model_name LIKE 'Original_model%';

SELECT sign_id
FROM model_performance
WHERE model_type = 'night' AND accuracy >= 94.5283;

SELECT COUNT(*) 
FROM users 
WHERE role IN ('data analyst', 'model developer');

SELECT sign_id, total_images
FROM traffic_signs
WHERE category = 'Dangerous warning' AND sub_category = 'Prohibitory';

external_knowledge:
- "gardeners" refers to the users who made changes;
- "sown the seeds of change" refers to the updates made to traffic sign compliance records;
- "traffic signs to flourish" refers to the traffic signs that have been updated;
- "from the realm of compliance shadows into the light of acceptance" refers to the transition of the compliance status to 'passed';
- "more than once" refers to the condition where the count of changes for a traffic sign is greater than one.

